parameters.jsCode:
const ollamaResponse = $('Ollama - Generar Respuesta').first().json;
const clientData = $('Preparar Prompt + Catalogo').first().json.clientData;

const respuestaIA = ollamaResponse?.choices?.[0]?.message?.content || 'Disculpá, tuve un problema técnico. Escribinos directo por WhatsApp: https://wa.me/5491127967222';
const tokensUsados = ollamaResponse?.usage?.total_tokens || 0;
const quiereComprar = /comprar|lo quiero|me interesa|disponible|reserv|lo llevo/i.test(clientData.mensaje);
const modeloMencionado = clientData.mensaje.match(/iphone\s*\d{2}\s*(pro\s*max|pro|plus)?/i)?.[0] || 'no detectado';

return {
  json: {
    success: true,
    respuesta: respuestaIA,
    telefono: clientData.telefono,
    nombre: clientData.nombre,
    mensajeOriginal: clientData.mensaje,
    timestamp: clientData.timestamp,
    dolarBlue: clientData.dolarBlue,
    tokensUsados,
    modeloDetectado: modeloMencionado,
    intencionCompra: quiereComprar,
    modelo: 'llama3.1 (Ollama local)'
  }
};
